package controllers

import java.nio.file.{Files, Path, Paths, StandardOpenOption}
import javax.inject._
import play.api.mvc._
import scala.concurrent.ExecutionContext
import scala.io.Source

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents)(implicit ec: ExecutionContext)
    extends BaseController {

  private val baseDir: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def serve(filename: String): Action[AnyContent] = Action {
    val requestedPath = baseDir.resolve(filename).normalize()

    if (!requestedPath.startsWith(baseDir) || !Files.exists(requestedPath) || !Files.isRegularFile(requestedPath)) {
      NotFound("File not found")
    } else {
      val source = Source.fromFile(requestedPath.toFile)
      try {
        val content = source.mkString
        Ok(content)
      } finally {
        source.close()
      }
    }
  }
}